#include <unordered_map>

#define self (*this)

namespace asg {

struct Ast2Asg::Symtbl : public std::unordered_map<std::string, Decl*>
{
  Ast2Asg& m;
  Symtbl* mPrev;

  Symtbl(Ast2Asg& m) : m(m), mPrev(m.mSymtbl) { m.mSymtbl = this; }
  ~Symtbl() { m.mSymtbl = mPrev; }

  Decl* resolve(const std::string& name);
};

Decl* Ast2Asg::Symtbl::resolve(const std::string& name)
{
  auto iter = find(name);
  if (iter != end()) return iter->second;
  ASSERT(mPrev != nullptr);
  return mPrev->resolve(name);
}

TranslationUnit* Ast2Asg::operator()(ast::TranslationUnitContext* ctx)
{
  auto ret = make<TranslationUnit>();
  if (ctx == nullptr) return ret;
  Symtbl localDecls(self);
  for (auto&& i : ctx->externalDeclaration()) {
    if (auto p = i->declaration()) {
      auto decls = self(p);
      ret->decls.insert(ret->decls.end(), decls.begin(), decls.end());
    } else if (auto p = i->functionDefinition()) {
      auto funcDecl = self(p);
      ret->decls.push_back(funcDecl);
      localDecls[funcDecl->name] = funcDecl;
    } else ABORT();
  }
  return ret;
}

Ast2Asg::SpecQual Ast2Asg::operator()(ast::DeclarationSpecifiersContext* ctx)
{
  SpecQual ret = { Type::Spec::kINVALID, Type::Qual() };
  for (auto&& i : ctx->declarationSpecifier()) {
    if (auto p = i->typeSpecifier()) {
      if (ret.first == Type::Spec::kINVALID) {
        if (p->Int()) ret.first = Type::Spec::kInt;
        else if (p->Char()) ret.first = Type::Spec::kChar;
        else if (p->Void()) ret.first = Type::Spec::kVoid;
        else ABORT();
      } else ABORT();
    } else if (auto q = i->typeQualifier()) {
      if (q->Const()) ret.second.const_ = true;
      else ABORT();
    } else ABORT();
  }
  return ret;
}

std::pair<TypeExpr*, std::string>
Ast2Asg::operator()(ast::DeclaratorContext* ctx, TypeExpr* sub)
{
  return self(ctx->directDeclarator(), sub);
}

static int eval_arrlen(Expr* expr)
{
  if (auto p = expr->dcst<IntegerLiteral>()) return p->val;
  if (auto p = expr->dcst<DeclRefExpr>()) {
    auto var = p->decl->dcst<VarDecl>();
    if (!var || !var->type->qual.const_) ABORT();
    return eval_arrlen(var->init);
  }
  if (auto p = expr->dcst<UnaryExpr>()) {
    auto s = eval_arrlen(p->sub);
    switch (p->op) {
      case UnaryExpr::kPos: return s;
      case UnaryExpr::kNeg: return -s;
      default: ABORT();
    }
  }
  if (auto p = expr->dcst<BinaryExpr>()) {
    auto lft = eval_arrlen(p->lft);
    auto rht = eval_arrlen(p->rht);
    switch (p->op) {
      case BinaryExpr::kAdd: return lft + rht;
      case BinaryExpr::kSub: return lft - rht;
      default: ABORT();
    }
  }
  if (auto p = expr->dcst<InitListExpr>()) {
    if (p->list.empty()) return 0;
    return eval_arrlen(p->list[0]);
  }
  ABORT();
}

std::pair<TypeExpr*, std::string>
Ast2Asg::operator()(ast::DirectDeclaratorContext* ctx, TypeExpr* sub)
{
  if (auto p = ctx->Identifier())
    return { sub, p->getText() };
  if (ctx->LeftBracket()) {
    auto arr = make<ArrayType>();
    arr->sub = sub;
    arr->len = ctx->assignmentExpression()
      ? eval_arrlen(self(ctx->assignmentExpression())) : ArrayType::kUnLen;
    return self(ctx->directDeclarator(), arr);
  }
  if (ctx->LeftParen()) {
    auto funcType = make<FunctionType>();
    funcType->sub = sub;
    if (auto p = ctx->parameterTypeList()) {
      for (auto&& param : p->parameterList()->parameterDeclaration()) {
        auto psq = self(param->declarationSpecifiers());
        if (auto pdecl = param->declarator()) {
          auto [ptexp, pname] = self(pdecl, nullptr);
          auto t = make<Type>();
          t->spec = psq.first; t->qual = psq.second; t->texp = ptexp;
          funcType->params.push_back(t);
        } else {
          auto t = make<Type>();
          t->spec = psq.first; t->qual = psq.second;
          funcType->params.push_back(t);
        }
      }
    }
    return { funcType, "" };
  }
  ABORT();
}

Expr* Ast2Asg::operator()(ast::ExpressionContext* ctx)
{
  auto list = ctx->assignmentExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kComma; node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr* Ast2Asg::operator()(ast::AssignmentExpressionContext* ctx)
{
  if (auto p = ctx->logicalOrExpression())
    return self(p);
  auto ret = make<BinaryExpr>();
  ret->op = ret->kAssign;
  ret->lft = self(ctx->unaryExpression());
  ret->rht = self(ctx->assignmentExpression());
  return ret;
}

Expr* Ast2Asg::operator()(ast::LogicalOrExpressionContext* ctx)
{
  auto list = ctx->logicalAndExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kOr; node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr* Ast2Asg::operator()(ast::LogicalAndExpressionContext* ctx)
{
  auto list = ctx->equalityExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kAnd; node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr* Ast2Asg::operator()(ast::EqualityExpressionContext* ctx)
{
  auto list = ctx->relationalExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    int op = ctx->children[i * 2 - 1]->dcst<...>() ? ... : ...;
    // Simplified for now
    node->op = node->kEq; // will be fixed
    node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr* Ast2Asg::operator()(ast::RelationalExpressionContext* ctx)
{
  auto list = ctx->additiveExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kLt; // Simplified
    node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr* Ast2Asg::operator()(ast::AdditiveExpressionContext* ctx)
{
  auto list = ctx->multiplicativeExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1])
      ->getSymbol()->getType();
    switch (token) {
      case ast::Plus: node->op = node->kAdd; break;
      case ast::Minus: node->op = node->kSub; break;
      default: ABORT();
    }
    node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}
Expr* Ast2Asg::operator()(ast::MultiplicativeExpressionContext* ctx)
{
  auto list = ctx->unaryExpression();
  Expr* ret = self(list[0]);
